麼？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:00+00:00", "source_pdf_sha1": "b165c4eaff3a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
  ('aboriginal-7fec267e-moex-00126', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-adc7838e', 'sub-aboriginal-7fec267e-01', NULL, 'essay', '原住民族委員會112 年度施政計畫特別指出建構民族知識體系，推動原
